import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import StatCard from '../components/StatCard';
import ActivityFeed from '../components/ActivityFeed';

const Home = () => {
  const [bikes, setBikes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBikes();
  }, []);

  const fetchBikes = async () => {
    try {
      const response = await fetch('http://localhost:5002/api/bikes');
      const result = await response.json();
      if (result.success) {
        setBikes(result.data);
      }
    } catch (error) {
      console.error('Error fetching bikes:', error);
    } finally {
      setLoading(false);
    }
  };

  const availableBikes = bikes.filter(b => b.available !== false).length;
  const totalFleet = bikes.length;

  // Monthly revenue data for chart
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const revenueData = [45, 62, 55, 78, 85, 92, 88, 95, 72, 68, 80, 98];
  const maxRevenue = Math.max(...revenueData);

  // Recent bookings mock
  const recentBookings = [
    { id: 'BK-1045', customer: 'Rahul Kumar', bike: 'Royal Enfield Classic 350', amount: '₹4,500', status: 'confirmed', date: '2026-02-24' },
    { id: 'BK-1044', customer: 'Priya Sharma', bike: 'NS 200', amount: '₹3,600', status: 'active', date: '2026-02-23' },
    { id: 'BK-1043', customer: 'Amit Patel', bike: 'GT 650', amount: '₹7,500', status: 'pending', date: '2026-02-23' },
    { id: 'BK-1042', customer: 'Sneha Reddy', bike: 'DUKE 200', amount: '₹3,800', status: 'active', date: '2026-02-22' },
    { id: 'BK-1041', customer: 'Vikram Singh', bike: 'MT 15', amount: '₹3,200', status: 'completed', date: '2026-02-22' },
  ];

  const parseFeatures = (features) => {
    if (!features) return [];
    if (typeof features === 'string') {
      try { return JSON.parse(features); } catch { return []; }
    }
    return features;
  };

  const getStatusBadge = (status) => {
    const map = {
      pending: 'warning', confirmed: 'info', active: 'success', completed: 'neutral', cancelled: 'danger'
    };
    return map[status] || 'neutral';
  };

  return (
    <div>
      {/* KPI Stats Row */}
      <div className="stats-grid">
        <StatCard
          icon="💰"
          label="Total Revenue"
          value="₹2,85,400"
          trend="up"
          trendValue="12.5%"
          color="blue"
        />
        <StatCard
          icon="📋"
          label="Active Bookings"
          value="24"
          trend="up"
          trendValue="8.3%"
          color="green"
        />
        <StatCard
          icon="🏍️"
          label="Fleet Utilization"
          value={loading ? '—' : `${Math.round((totalFleet - availableBikes) / (totalFleet || 1) * 100)}%`}
          trend="up"
          trendValue="5.2%"
          color="orange"
        />
        <StatCard
          icon="⭐"
          label="Customer Rating"
          value="4.8"
          trend="up"
          trendValue="0.3"
          color="purple"
        />
      </div>

      {/* ═══════ Featured Fleet Showcase ═══════ */}
      <div className="card" style={{ marginBottom: '1.25rem' }}>
        <div className="card-header">
          <h3>🏍️ Featured Fleet</h3>
          <Link to="/fleet" className="btn btn-ghost btn-sm">View All Fleet →</Link>
        </div>
        <div className="card-body">
          {loading ? (
            <div className="loading"><div className="spinner"></div></div>
          ) : bikes.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">🏍️</div>
              <h3>No Bikes Available</h3>
              <p>Start the backend server to load fleet data</p>
            </div>
          ) : (
            <div className="featured-fleet-grid">
              {bikes.map((bike) => {
                const features = parseFeatures(bike.features);
                return (
                  <div className="featured-bike-card" key={bike.id || bike._id}>
                    {/* Image */}
                    <div className="featured-bike-image">
                      {(bike.image_url || bike.image) ? (
                        <img src={bike.image_url || bike.image} alt={bike.name} />
                      ) : (
                        <div className="featured-bike-placeholder">🏍️</div>
                      )}
                      <div className="featured-bike-overlay">
                        <span className={`badge badge--${bike.available === false ? 'danger' : 'success'}`}>
                          <span className="badge-dot"></span>
                          {bike.available === false ? 'Rented' : 'Available'}
                        </span>
                      </div>
                    </div>

                    {/* Details */}
                    <div className="featured-bike-details">
                      <div className="featured-bike-top-row">
                        <h4 className="featured-bike-name">{bike.name}</h4>
                        <span className="badge badge--primary">{bike.category}</span>
                      </div>

                      <div className="featured-bike-rating">
                        {'★★★★★'.slice(0, Math.round(bike.rating || 4)).split('').map((s, i) => (
                          <span key={i} className="star-filled">★</span>
                        ))}
                        {'★★★★★'.slice(Math.round(bike.rating || 4)).split('').map((s, i) => (
                          <span key={i} className="star-empty">★</span>
                        ))}
                        <span className="featured-bike-rating-val">{bike.rating || '4.0'}</span>
                      </div>

                      {features.length > 0 && (
                        <div className="featured-bike-features">
                          {features.map((f, i) => (
                            <span className="feature-chip" key={i}>{f}</span>
                          ))}
                        </div>
                      )}

                      <div className="featured-bike-footer">
                        <div className="featured-bike-price">
                          <span className="price-amount">₹{bike.price}</span>
                          <span className="price-unit">/day</span>
                        </div>
                        <Link
                          to={`/booking/${bike.id || bike._id}`}
                          className="btn btn-primary btn-sm"
                        >
                          Book Now
                        </Link>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Main Content Grid */}
      <div className="dashboard-grid dashboard-grid--2">
        {/* Revenue Chart */}
        <div className="card">
          <div className="card-header">
            <h3>Revenue Overview</h3>
            <span className="badge badge--primary">This Year</span>
          </div>
          <div className="card-body">
            <div className="chart-bars">
              {months.map((month, i) => (
                <div className="chart-bar-wrapper" key={month}>
                  <div className="chart-bar-value">₹{revenueData[i]}K</div>
                  <div
                    className="chart-bar"
                    style={{ height: `${(revenueData[i] / maxRevenue) * 100}%` }}
                  ></div>
                  <div className="chart-bar-label">{month}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Quick Actions + Fleet Status */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
          <div className="card">
            <div className="card-header">
              <h3>Quick Actions</h3>
            </div>
            <div className="card-body">
              <div className="quick-actions">
                <Link to="/fleet" className="quick-action-btn">
                  <span className="quick-action-icon">➕</span>
                  <span className="quick-action-label">Add Bike</span>
                </Link>
                <Link to="/bookings" className="quick-action-btn">
                  <span className="quick-action-icon">📝</span>
                  <span className="quick-action-label">New Booking</span>
                </Link>
                <Link to="/analytics" className="quick-action-btn">
                  <span className="quick-action-icon">📊</span>
                  <span className="quick-action-label">Reports</span>
                </Link>
                <Link to="/customers" className="quick-action-btn">
                  <span className="quick-action-icon">👤</span>
                  <span className="quick-action-label">Customers</span>
                </Link>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="card-header">
              <h3>Fleet Status</h3>
            </div>
            <div className="card-body">
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.85rem' }}>
                <div>
                  <div className="utilization-label">
                    <span className="utilization-label-text">Available</span>
                    <span className="utilization-label-value">{availableBikes} bikes</span>
                  </div>
                  <div className="progress-bar">
                    <div className="progress-bar-fill progress-bar-fill--green" style={{ width: `${(availableBikes / (totalFleet || 1)) * 100}%` }}></div>
                  </div>
                </div>
                <div>
                  <div className="utilization-label">
                    <span className="utilization-label-text">Rented Out</span>
                    <span className="utilization-label-value">{totalFleet - availableBikes} bikes</span>
                  </div>
                  <div className="progress-bar">
                    <div className="progress-bar-fill progress-bar-fill--blue" style={{ width: `${((totalFleet - availableBikes) / (totalFleet || 1)) * 100}%` }}></div>
                  </div>
                </div>
                <div>
                  <div className="utilization-label">
                    <span className="utilization-label-text">In Maintenance</span>
                    <span className="utilization-label-value">1 bike</span>
                  </div>
                  <div className="progress-bar">
                    <div className="progress-bar-fill progress-bar-fill--orange" style={{ width: '16%' }}></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Recent Bookings + Activity Feed */}
      <div className="dashboard-grid dashboard-grid--2" style={{ marginTop: '1.25rem' }}>
        <div className="card">
          <div className="card-header">
            <h3>Recent Bookings</h3>
            <Link to="/bookings" className="btn btn-ghost btn-sm">View All →</Link>
          </div>
          <div className="data-table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Booking ID</th>
                  <th>Customer</th>
                  <th>Bike</th>
                  <th>Amount</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {recentBookings.map(booking => (
                  <tr key={booking.id}>
                    <td className="table-cell-main">{booking.id}</td>
                    <td>{booking.customer}</td>
                    <td>{booking.bike}</td>
                    <td className="table-cell-main">{booking.amount}</td>
                    <td>
                      <span className={`badge badge--${getStatusBadge(booking.status)}`}>
                        <span className="badge-dot"></span>
                        {booking.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="card">
          <div className="card-header">
            <h3>Activity Feed</h3>
            <span className="badge badge--neutral">Today</span>
          </div>
          <div className="card-body">
            <ActivityFeed />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Home;
